# Build all ticket rows from the templates
def build_tickets(templates, category, count=100):
    rows = []
    # Cycle through templates to reach desired count
    for i in range(count):
        tmpl = templates[i % len(templates)]
        intent, instruction, response = tmpl
        # Add light variation to instructions to avoid exact duplicates
        variations = [
            instruction,
            instruction.replace("I ", "We ").replace("my ", "our ") if "I " in instruction else instruction,
            "Hi, " + instruction[0].lower() + instruction[1:],
            instruction + " Please help.",
            "Hello, " + instruction[0].lower() + instruction[1:],
        ]
        final_instruction = variations[i % len(variations)]
        rows.append({
            "flags": "",
            "instruction": final_instruction,
            "category": category,
            "intent": intent,
            "response": response,
        })
    return rows

print("Generating 400 synthetic tickets (100 per category)...")
new_rows = []
new_rows.extend(build_tickets(ACCOUNT_TICKETS,  "ACCOUNT",  100))
new_rows.extend(build_tickets(PAYMENT_TICKETS,  "PAYMENT",  100))
new_rows.extend(build_tickets(SHIPPING_TICKETS, "SHIPPING", 100))
new_rows.extend(build_tickets(REFUND_TICKETS,   "REFUND",   100))

new_df = pd.DataFrame(new_rows)

# Load existing 500-ticket dataset
print("Loading existing tickets.csv...")
existing_df = pd.read_csv("data/tickets.csv")

# Combine and save
combined_df = pd.concat([existing_df, new_df], ignore_index=True)
output_path = "data/tickets_augmented.csv"
combined_df.to_csv(output_path, index=False)

print(f"\nSaved {len(combined_df)} total tickets to {output_path}")
print("\nTickets per category:")
print(combined_df["category"].value_counts().to_string())
